import{_ as i,o,c as a,ag as l}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"vex-pm Reference","description":"","frontmatter":{},"headers":[],"relativePath":"references/vex-pm-reference.md","filePath":"references/vex-pm-reference.md"}'),r={name:"references/vex-pm-reference.md"};function c(n,e,t,d,s,u){return o(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="vex-pm-reference" tabindex="-1">vex-pm Reference <a class="header-anchor" href="#vex-pm-reference" aria-label="Permalink to &quot;vex-pm Reference&quot;">​</a></h1><p>This document describes <code>vex-pm</code> package management and build integration responsibilities.</p><hr><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p><code>vex-pm</code> is responsible for:</p><ul><li>manifest parsing (<code>vex.json</code>)</li><li>dependency resolution and lock-file behavior</li><li>cache management</li><li>platform-aware module resolution</li><li>native dependency build/link argument generation</li></ul><hr><h2 id="core-modules" tabindex="-1">Core Modules <a class="header-anchor" href="#core-modules" aria-label="Permalink to &quot;Core Modules&quot;">​</a></h2><ul><li><code>tools/vex-pm/src/manifest.rs</code><ul><li><code>Manifest</code>, <code>NativeConfig</code>, <code>NativeFeatureConfig</code>, testing/workspace fields</li></ul></li><li><code>tools/vex-pm/src/build.rs</code><ul><li>dependency path resolution</li><li>native linker arg aggregation APIs</li></ul></li><li><code>tools/vex-pm/src/native_linker.rs</code><ul><li>C source compilation</li><li>pkg-config probing</li><li>feature merge and linker arg generation</li></ul></li><li><code>tools/vex-pm/src/resolver.rs</code><ul><li>dependency graph resolution</li></ul></li><li><code>tools/vex-pm/src/lockfile.rs</code><ul><li>lock integrity and deterministic dependency selection</li></ul></li><li><code>tools/vex-pm/src/cache.rs</code><ul><li>local package/git cache logic</li></ul></li></ul><hr><h2 id="manifest-semantics" tabindex="-1">Manifest Semantics <a class="header-anchor" href="#manifest-semantics" aria-label="Permalink to &quot;Manifest Semantics&quot;">​</a></h2><p><code>vex.json</code> can define:</p><ul><li>package metadata (<code>name</code>, <code>version</code>, <code>main</code>)</li><li>dependency map</li><li>testing/workspace config</li><li>native config (<code>native</code>)</li></ul><p><code>native</code> supports:</p><ul><li><code>sources</code>, <code>include_dirs</code>, <code>search_paths</code></li><li><code>libraries</code>, <code>cflags</code></li><li><code>pkg_config</code>, <code>pkg_config_optional</code></li><li><code>features</code> blocks with the same native fragment fields</li></ul><hr><h2 id="dependency-resolution" tabindex="-1">Dependency Resolution <a class="header-anchor" href="#dependency-resolution" aria-label="Permalink to &quot;Dependency Resolution&quot;">​</a></h2><p><code>resolve_dependencies_for_build(locked)</code>:</p><ul><li><code>locked=true</code>: requires valid <code>vex.lock</code></li><li><code>locked=false</code>: uses lock if valid; otherwise re-resolves</li></ul><p>Output is <code>DependencyPaths</code> with:</p><ul><li>package source directories</li><li>platform-specific file mappings</li></ul><hr><h2 id="native-link-aggregation-apis" tabindex="-1">Native Link Aggregation APIs <a class="header-anchor" href="#native-link-aggregation-apis" aria-label="Permalink to &quot;Native Link Aggregation APIs&quot;">​</a></h2><h3 id="get-native-linker-args-for-build-locked" tabindex="-1"><code>get_native_linker_args_for_build(locked)</code> <a class="header-anchor" href="#get-native-linker-args-for-build-locked" aria-label="Permalink to &quot;`get_native_linker_args_for_build(locked)`&quot;">​</a></h3><p>Collects native linker args from:</p><ul><li>current package manifest</li><li>resolved dependency manifests</li></ul><h3 id="get-native-linker-args-for-source-source-locked" tabindex="-1"><code>get_native_linker_args_for_source(source, locked)</code> <a class="header-anchor" href="#get-native-linker-args-for-source-source-locked" aria-label="Permalink to &quot;`get_native_linker_args_for_source(source, locked)`&quot;">​</a></h3><p>Extends build-level collection with stdlib package manifests discovered from imports in source.</p><p>This is used by <code>vex-cli</code> so imported stdlib modules (for example <code>db</code>) can contribute native build/link settings automatically.</p><hr><h2 id="nativelinker-behavior" tabindex="-1">NativeLinker Behavior <a class="header-anchor" href="#nativelinker-behavior" aria-label="Permalink to &quot;NativeLinker Behavior&quot;">​</a></h2><p><code>NativeLinker::process(...)</code> performs:</p><ol><li>effective config materialization (base + enabled features)</li><li>pkg-config resolution (optional/strict behavior)</li><li>macro-aware source gating (<code>HAVE_*</code> checks)</li><li>C compilation to objects</li><li>dynamic linker arg generation (<code>-L</code>, <code>-l</code>, object list)</li></ol><p>Policy:</p><ul><li>static linking is not allowed in this architecture (<code>static_libs</code> rejected)</li></ul><hr><h2 id="environment-controls" tabindex="-1">Environment Controls <a class="header-anchor" href="#environment-controls" aria-label="Permalink to &quot;Environment Controls&quot;">​</a></h2><ul><li><code>VEX_NATIVE_FEATURES=feat1,feat2</code></li><li><code>VEX_DB_FEATURES=...</code> (compat alias)</li><li><code>PKG_CONFIG_PATH=...</code></li></ul><hr><h2 id="cache-and-determinism" tabindex="-1">Cache and Determinism <a class="header-anchor" href="#cache-and-determinism" aria-label="Permalink to &quot;Cache and Determinism&quot;">​</a></h2><ul><li>package/git cache rooted in <code>~/.vex/cache</code> (or <code>VEX_CACHE</code>)</li><li>lock-file validation prevents drift in CI/locked mode</li></ul><hr><h2 id="design-notes" tabindex="-1">Design Notes <a class="header-anchor" href="#design-notes" aria-label="Permalink to &quot;Design Notes&quot;">​</a></h2><ul><li><code>vex-pm</code> provides policy + metadata resolution</li><li><code>vex-cli</code> consumes resolved paths/args to execute compile/run/test workflows</li><li>package-native behavior should remain manifest-driven, not command-hardcoded</li></ul><hr><h2 id="related-references" tabindex="-1">Related References <a class="header-anchor" href="#related-references" aria-label="Permalink to &quot;Related References&quot;">​</a></h2><ul><li><a href="./vex-cli-reference">vex-cli Reference</a></li><li><a href="./vex-pm-native-ffi">vex-pm Native FFI Pipeline</a></li></ul>',47)])])}const m=i(r,[["render",c]]);export{h as __pageData,m as default};
